// // When abc is 000, q should be 1; when abc is 110, q should be 1; when abc is 101, q should be 0; when abc is 111, q should be 0; when abc is 100, q should be 0; when abc is 010, q should be 1; when abc is 001, q should be 1; when abc is 011, q should be 1
module top_module (
    input a,
    input b,
    input c,
    output reg q
);
    always @(*) begin
        case ({a, b, c})
            3'b000: q = 1'b0;
            3'b110: q = 1'b0;
            3'b101: q = 1'b1;
            3'b111: q = 1'b1;
            3'b100: q = 1'b1;
            3'b010: q = 1'b0;
            3'b001: q = 1'b0;
            3'b011: q = 1'b0;
        endcase
    end
endmodule
